#include <stdio.h>
#include <stdlib.h>
#define MOD 500009
#define LIMIT 8000000
int main(){
    static int divcnt[LIMIT+1];
    static int freq[256]; // divisor count never exceeds 255 for this limit
    static int ans[LIMIT+1];
    // sieve for divisor counts
    for(int i=1;i<=LIMIT;i++){
        for(int j=i;j<=LIMIT;j+=i) divcnt[j]++;
    }
    ans[0]=1;
    for(int i=1;i<=LIMIT;i++){
        int d=divcnt[i];
        freq[d]++;
        long long cur=ans[i-1];
        cur = (cur * freq[d]) % MOD;
        ans[i]=(int)cur;
    }
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        if(N>LIMIT) printf("0\n");
        else printf("%d\n", ans[N]);
    }
    return 0;
}

