    ans[0]=1;
    for(int i=1;i<=LIMIT;i++){
        int d = divcnt[i];
        ++freq[d];
        ans[i] = (int)((1LL*ans[i-1]*freq[d])%MOD);
    }
    int T; if(!(cin>>T)) return 0;
    while(T--){
        long long N; cin>>N;
        if(N>LIMIT) cout<<0<<'\n';
        else cout<<ans[N]<<'\n';
    }
    return 0;
}

